#include <stdio.h>

typedef enum { OP_ADD, OP_SUB, OP_MUL, OP_DIV, OP_COUNT } Op;

int op_add(int a, int b) { return a + b; }
int op_sub(int a, int b) { return a - b; }
int op_mul(int a, int b) { return a * b; }
int op_div(int a, int b) { return b != 0 ? a / b : 0; }

static const char *op_names[] = {"+", "-", "*", "/"};

typedef int (*OpFunc)(int, int);

int main(void) {
    OpFunc dispatch[OP_COUNT] = {op_add, op_sub, op_mul, op_div};
    int pairs[][2] = {{10, 3}, {20, 4}, {7, 2}, {15, 5}};

    for (int op = 0; op < OP_COUNT; op++) {
        int a = pairs[op][0], b = pairs[op][1];
        int result = dispatch[op](a, b);
        printf("%d %s %d = %d\n", a, op_names[op], b, result);
    }
    return 0;
}

